#include<bits/stdc++.h>
using namespace std;

vector<int> e[100005];
int cnt = 0;
int a[100005];

void dfs(int u, int p)
{
	if(a[u]) return;
	a[u] = p;
	for(int v : e[u])
		dfs(v, p);
}

int main()
{
	int n, m, ans = 0;
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int u, v;
		cin >> u >> v;
		e[v].push_back(u);
	}
	for(int i = n; i >= 1; i--)
	{
		if(a[i]) continue;
		dfs(i, i);
	}
	for(int i = 1; i <= n; i++)
		cout << a[i] << ' ';
	return 0;
}
